create table dirkspzm32.pe_drucker_cfg (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    drucker_name         varchar2(255 char) not null enable,
    drucker_typ          varchar2(10 char) not null enable,
    caption              varchar2(30 char) not null enable,
    computername         varchar2(30 char),
    ort_beschreibung     varchar2(500 char),
    com_name             varchar2(15 char),
    eti_drucker_typ      varchar2(50 char),
    visu_name            varchar2(255 char),
    visu_poll_msek       number(*, 12),
    status               varchar2(10 char),
    status_txt           varchar2(255 char),
    eti_output_type      varchar2(10 char),
    win_drucker          varchar2(255 char),
    pause_after_job_ms   number(*, 12) default 300,
    print_folder_path    varchar2(255 char),
    created_date         date,
    created_login_id     number(*, 0),
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.pe_drucker_cfg
    add constraint pk_drucker_cfg
        primary key ( sid,
                      firma_nr,
                      drucker_name )
            using index enable;


